B.P2=new A.an("Malkhut governs Shabbat. Ground yourself in the physical \u2014 rest, eat mindfully, be present.","\u041c\u0430\u043b\u0445\u0443\u0442 \u043f\u0440\u0430\u0432\u0438\u0442 \u0428\u0430\u0431\u0431\u0430\u0442\u043e\u043c. \u0417\u0430\u0437\u0435\u043c\u043b\u0438\u0441\u044c \u0432 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u043e\u043c \u2014 \u043e\u0442\u0434\u044b\u0445\u0430\u0439, \u0435\u0448\u044c \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e, \u0431\u0443\u0434\u044c \u0432 \u043c\u043e\u043c\u0435\u043d\u0442\u0435.","cosmic_weekday_11",null)
